namespace sv_d3c4c7129d4b4b8497ec0593e45e7048.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors = ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly Dictionary<string, List<string>> TimeSlots = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Williams"] = ["9:00 AM", "10:30 AM", "2:30 PM", "3:30 PM"],
        ["Dr. Brown"] = ["8:30 AM", "10:00 AM", "11:30 AM", "3:00 PM"]
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        var slots = TimeSlots.GetValueOrDefault(doctor, []);
        return Task.FromResult(slots);
    }

    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email, string insuranceProvider, string doctor, string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(AppointmentModel.Email)] = ["Account has outstanding balance"];
        }

        // Reject self-pay with Dr. Smith
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(AppointmentModel.Doctor)] = ["Selected doctor does not accept self-pay patients"];
        }

        // Reject 10:00 AM slot as taken
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(AppointmentModel.TimeSlot)] = ["This slot is no longer available"];
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_d3c4c7129d4b4b8497ec0593e45e7048.Services;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    [Required(ErrorMessage = "Please select a doctor.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Appointment date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string? Reason { get; set; }
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult(ErrorMessage);
        }
        return ValidationResult.Success;
    }
}

@using Microsoft.AspNetCore.Components.Forms

@code {
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_d3c4c7129d4b4b8497ec0593e45e7048.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h2>Step 1: Patient Information</h2>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="CheckAvailability">
            Check Availability
        </button>
    }

    @if (showStep2)
    {
        <h2>Step 2: Appointment Details</h2>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.Doctor" @bind:after="OnDoctorChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.Reason" rows="4" />
            <ValidationMessage For="() => model.Reason" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Booking..." : "Book Appointment")
        </button>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
}

@code {
    private AppointmentModel model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();

        // Validate only step 1 fields
        var isValid = true;
        var step1Fields = new[] { nameof(model.PatientName), nameof(model.Email), nameof(model.Phone), nameof(model.InsuranceProvider) };

        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
        }

        // Check if step 1 fields have validation errors
        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                isValid = false;
            }
        }

        if (!isValid) return;

        // Run server-side validation with current values
        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email ?? "", model.InsuranceProvider ?? "",
            model.Doctor ?? "", model.TimeSlot ?? "");

        // Only show email-related errors from step 1 check
        var step1Errors = errors
            .Where(e => e.Key == nameof(AppointmentModel.Email))
            .ToDictionary(e => e.Key, e => e.Value);

        if (step1Errors.Count > 0)
        {
            customValidator!.DisplayErrors(step1Errors);
            return;
        }

        showStep2 = true;
    }

    private async Task OnDoctorChanged()
    {
        availableSlots = [];
        model.TimeSlot = null;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Doctor, model.AppointmentDate.Value);
        }
    }

    private async Task OnDateChanged()
    {
        availableSlots = [];
        model.TimeSlot = null;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Doctor, model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        customValidator?.ClearErrors();

        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email ?? "", model.InsuranceProvider ?? "",
            model.Doctor ?? "", model.TimeSlot ?? "");

        if (errors.Count > 0)
        {
            customValidator!.DisplayErrors(errors);
            isSubmitting = false;
            return;
        }

        // Simulate booking
        await Task.Delay(500);
        bookingConfirmed = true;
        isSubmitting = false;
    }
}

