@page "/book-appointment"
@rendermode InteractiveServer
@using sv_d3c4c7129d4b4b8497ec0593e45e7048.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h2>Step 1: Patient Information</h2>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="CheckAvailability">
            Check Availability
        </button>
    }

    @if (showStep2)
    {
        <h2>Step 2: Appointment Details</h2>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.Doctor" @bind:after="OnDoctorChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.Reason" rows="4" />
            <ValidationMessage For="() => model.Reason" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Booking..." : "Book Appointment")
        </button>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
}

@code {
    private AppointmentModel model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();

        // Validate only step 1 fields
        var isValid = true;
        var step1Fields = new[] { nameof(model.PatientName), nameof(model.Email), nameof(model.Phone), nameof(model.InsuranceProvider) };

        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
        }

        // Check if step 1 fields have validation errors
        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                isValid = false;
            }
        }

        if (!isValid) return;

        // Run server-side validation with current values
        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email ?? "", model.InsuranceProvider ?? "",
            model.Doctor ?? "", model.TimeSlot ?? "");

        // Only show email-related errors from step 1 check
        var step1Errors = errors
            .Where(e => e.Key == nameof(AppointmentModel.Email))
            .ToDictionary(e => e.Key, e => e.Value);

        if (step1Errors.Count > 0)
        {
            customValidator!.DisplayErrors(step1Errors);
            return;
        }

        showStep2 = true;
    }

    private async Task OnDoctorChanged()
    {
        availableSlots = [];
        model.TimeSlot = null;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Doctor, model.AppointmentDate.Value);
        }
    }

    private async Task OnDateChanged()
    {
        availableSlots = [];
        model.TimeSlot = null;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(model.Doctor, model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        customValidator?.ClearErrors();

        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email ?? "", model.InsuranceProvider ?? "",
            model.Doctor ?? "", model.TimeSlot ?? "");

        if (errors.Count > 0)
        {
            customValidator!.DisplayErrors(errors);
            isSubmitting = false;
            return;
        }

        // Simulate booking
        await Task.Delay(500);
        bookingConfirmed = true;
        isSubmitting = false;
    }
}

